sandbox_exec = Agent(
    name="SandboxExecutor",
    instructions="Execute code in isolated Docker container. Capture stdout/stderr/exit code. Run pytest if tests exist.",
    tools=[docker_exec_tool, pytest_runner_tool],
    model="gpt-4o"
)

@tool
def docker_exec(code: str, filename: str) -> dict:
    '''Execute code in isolated Docker container'''
    with DockerClient() as client:
        container = client.containers.run(
            'python:3.11-slim',
            f'python /app/{filename}',
            volumes={'/sandbox': {'bind': '/app', 'mode': 'ro'}}
        )
    return {
        'stdout': container.logs(stdout=True).decode(),
        'stderr': container.logs(stderr=True).decode(),
        'exit_code': container.wait()['StatusCode']
    }
